const body = $input.first().json;

return {
  purchase_id: body.purchase_id,
  affiliate_id: body.affiliate_id,
  referral_code: body.referral_code,
  amount_cents: body.amount_cents || 0,
  product_type: body.product_type || 'tripwire',
  commission_pct: body.commission_pct || 40,
  referred_email: body.customer_email,
  referred_profile_id: body.profile_id || null,
  membership_id: body.membership_id || null,
  is_recurring: body.is_recurring || false
};

const amountCents = $json.amount_cents;
const commissionPct = $json.commission_pct || $json.commission_pct;
const isRecurring = $json.is_recurring;

let commissionCents = Math.round(amountCents * (commissionPct / 100));

// Tier bonuses
const tier = $json.tier || 'standard';
if (tier === 'premium') commissionCents = Math.round(commissionCents * 1.1);   // 10% bonus
if (tier === 'elite') commissionCents = Math.round(commissionCents * 1.25);     // 25% bonus

return {
  commission_cents: commissionCents,
  commission_type: isRecurring ? 'recurring' : 'one_time',
  commission_pct: commissionPct,
  effective_pct: ((commissionCents / amountCents) * 100).toFixed(2),
  affiliate_id: $json.id,
  purchase_id: $json.purchase_id
};

